#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e6+10,M=2e6+10;
int n,m,k;
int que[N],H,T,isBrute,tmp[N],deg[N],lis[N],pl,stk[N],top;
short vis[N];
inline void Solve()
{
    n=read();m=read();k=read();
    isBrute=((1ll*k*(k-1)>>1)<=m);//printf("aaaaaaaaa %d\n",isBrute);
    vector< vector<int> > G(n);
    rep(1,m,i)
    {
        int x=read()-1,y=read()-1;
        G[x].push_back(y);G[y].push_back(x);
    }
    top=0;memset(deg,0,(n+1)<<2);
    rep(0,n-1,i)
    {
        deg[i]=G[i].size();sort(G[i].begin(),G[i].end());
        if(deg[i]<k)stk[++top]=i;
    }
    memset(vis,0,(n+1)<<2);pl=0;memset(lis,0,(n+1)<<2);
    while(top)
    {
        int u=stk[top--];vis[u]=2;
        if(isBrute&&deg[u]==k-1&&!pl)
        {
//        	puts("QWQQWQWQQWQWQWQWQQWQWQWQWQWQWQWQWQWQWQW");
            lis[pl=1]=u;bool flag=0;
            for(int v: G[u])if(vis[v]^2)lis[++pl]=v;
//            rep(1,pl,i)printf("%d ",lis[i]);puts("");
            rep(1,pl,i)
            {
                int v=lis[i];rep(1,pl,j)
                {
                    int w=lis[j];if(v==w)continue;
                    int l=0,r=G[v].size(),mid,res=0;--r;
                    while(l<=r)G[v][mid=(l+r)>>1]<=w?(l=mid+1,res=mid):(r=mid-1);
                    if(G[v][res]^w){flag=1;break;}
                }
                if(flag){pl=0;break;}
            }
            if(pl==k){top=0;break;}else pl=0;
        }
        for(int v: G[u])if((--deg[v])==k-1&&!vis[v])vis[stk[++top]=v]=1;
    }
    if(pl){puts("2");rep(1,pl,i)printf("%d ",lis[i]+1);puts("");return;}
    int num=0;rep(0,n-1,u)if(!vis[u])++num;if(!num){puts("-1");return;}
    printf("1 %d\n",num);rep(0,n-1,u)if(!vis[u])printf("%d ",u+1);puts("");return;
}
int main()
{
//	freopen("data.txt","r",stdin);
	int T=read();while(T--)Solve();return 0;
}
